import{_ as t,C as s,o as r,c as n,ag as o,E as d,w as i,a as l}from"./chunks/framework.BZohXCq9.js";const _=JSON.parse('{"title":"Moneda y precios","description":"Cómo funciona el sistema de moneda en SYNTIweb","frontmatter":{"title":"Moneda y precios","description":"Cómo funciona el sistema de moneda en SYNTIweb"},"headers":[],"relativePath":"shared/moneda-y-precios.md","filePath":"shared/moneda-y-precios.md"}'),c={name:"shared/moneda-y-precios.md"};function m(u,e,p,g,b,h){const a=s("Tip");return r(),n("div",null,[e[1]||(e[1]=o('<p>SYNTIweb está diseñado para el mercado venezolano dolarizado. Puedes mostrar los precios de tus productos de varias formas según lo que le convenga a tu negocio.</p><h2 id="modos-de-moneda" tabindex="-1">Modos de moneda <a class="header-anchor" href="#modos-de-moneda" aria-label="Permalink to &quot;Modos de moneda&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Modo</th><th>Qué muestra</th><th>Ejemplo</th></tr></thead><tbody><tr><td><strong>Solo REF</strong></td><td>Precio en dólares de referencia</td><td><code>REF 5.00</code></td></tr><tr><td><strong>Solo bolívares</strong></td><td>Conversión automática con tasa BCV</td><td><code>Bs. 182.50</code></td></tr><tr><td><strong>REF y Bs. con toggle</strong></td><td>Tu cliente cambia entre los dos con un botón</td><td>REF ↔ Bs.</td></tr><tr><td><strong>Euro con toggle</strong></td><td>Euros y bolívares alternados</td><td>€ ↔ Bs.</td></tr><tr><td><strong>Ocultar precios</strong></td><td>No muestra precios, solo &quot;Más Info&quot;</td><td>Botón WhatsApp</td></tr></tbody></table><h2 id="cambiar-el-modo-de-moneda" tabindex="-1">Cambiar el modo de moneda <a class="header-anchor" href="#cambiar-el-modo-de-moneda" aria-label="Permalink to &quot;Cambiar el modo de moneda&quot;">​</a></h2><ol><li>Entra a tu panel (Alt+S o long press en el logo)</li><li>Ve a la pestaña <strong>Configuración</strong></li><li>Busca la sección <strong>Moneda</strong></li><li>Elige el modo que prefieras</li><li>Dale clic a <strong>Guardar</strong> — se aplica al instante</li></ol><h2 id="tasa-bcv-automatica" tabindex="-1">Tasa BCV automática <a class="header-anchor" href="#tasa-bcv-automatica" aria-label="Permalink to &quot;Tasa BCV automática&quot;">​</a></h2><p>Si usas bolívares, SYNTIweb actualiza la tasa BCV automáticamente cada día. No tienes que cambiar los precios manualmente cuando suba o baje el dólar.</p><p><strong>Ejemplo:</strong> Si tu producto cuesta REF 8.00 y la tasa BCV está a Bs. 36.50, tu cliente ve <code>Bs. 292.00</code> automáticamente.</p><h2 id="simbolo-configurable" tabindex="-1">Símbolo configurable <a class="header-anchor" href="#simbolo-configurable" aria-label="Permalink to &quot;Símbolo configurable&quot;">​</a></h2><p>Puedes elegir si el símbolo que aparece es <strong>REF</strong> o <strong>$</strong>. Los dos significan lo mismo — referencia en dólares. Elige el que prefieran tus clientes.</p>',10)),d(a,null,{default:i(()=>[...e[0]||(e[0]=[l(" El modo **REF y bolívares con toggle** es el favorito de los negocios venezolanos porque el cliente ve el precio en lo que prefiera sin confusión. ",-1)])]),_:1}),e[2]||(e[2]=o('<h2 id="ver-tambien" tabindex="-1">Ver también <a class="header-anchor" href="#ver-tambien" aria-label="Permalink to &quot;Ver también&quot;">​</a></h2><ul><li><a href="/studio/seccion-config.html">Configuración del panel</a> — Ajusta moneda, medios de pago y PIN</li><li><a href="/shared/cuenta-y-planes.html">Planes y precios</a> — Todos los planes con sus precios en REF</li><li><a href="/shared/glosario.html">Glosario</a> — Qué significa REF, BCV y otros términos</li></ul>',2))])}const T=t(c,[["render",m]]);export{_ as __pageData,T as default};
